def stream_squares(numbers):
    # A generator EXPRESSION: lazy, holds no intermediate list.
    return (n * n for n in numbers)

import itertools


def take_cases(batches, n):
    # Flatten the batches lazily with chain.from_iterable, then take the
    # first n with islice. Both are lazy: we never build the full flat list.
    flat = itertools.chain.from_iterable(batches)
    return list(itertools.islice(flat, n))

import itertools


def count_by_status(results):
    # results: iterable of (name, status). itertools.groupby only groups
    # ADJACENT equal keys, so sort by status first, then group.
    ordered = sorted(results, key=lambda r: r[1])
    counts = {}
    for status, group in itertools.groupby(ordered, key=lambda r: r[1]):
        # `group` is a one-shot sub-iterator; count its items.
        counts[status] = sum(1 for _ in group)
    return counts

