from solution import count_by_status


def test_counts_each_status():
    results = [
        ("test_a", "passed"),
        ("test_b", "failed"),
        ("test_c", "passed"),
        ("test_d", "passed"),
    ]
    assert count_by_status(results) == {"passed": 3, "failed": 1}


def test_empty_input():
    assert count_by_status([]) == {}


def test_single_status():
    results = [("t1", "skipped"), ("t2", "skipped")]
    assert count_by_status(results) == {"skipped": 2}


def test_unsorted_input_is_handled():
    # Tricky: itertools.groupby only groups ADJACENT equal keys. If the
    # solution forgets to sort, an interleaved status appears as several
    # separate groups and the counts are wrong. Here "passed" is split apart.
    results = [
        ("a", "passed"),
        ("b", "failed"),
        ("c", "passed"),
        ("d", "failed"),
        ("e", "passed"),
    ]
    assert count_by_status(results) == {"passed": 3, "failed": 2}


def test_works_on_a_one_shot_iterator():
    # The input may be a generator, consumable once.
    def gen():
        yield ("x", "error")
        yield ("y", "passed")
        yield ("z", "error")

    assert count_by_status(gen()) == {"error": 2, "passed": 1}

