import itertools


def case_stream(browsers, widths):
    # Yield (case_id, browser, width) for every (browser, width) combination,
    # cycling forever, with a 1-based incrementing id. Lazy and unbounded:
    # itertools.count drives the id, itertools.cycle repeats the combinations.
    combos = list(itertools.product(browsers, widths))
    ids = itertools.count(1)
    for browser, width in itertools.cycle(combos):
        yield (next(ids), browser, width)


def first_cases(browsers, widths, n):
    # Take the first n cases from the (possibly infinite) stream.
    return list(itertools.islice(case_stream(browsers, widths), n))
